-- ===================================================================
-- COURSE: Introduction to OpenMRS
-- ===================================================================
VALUES (UUID(), 5, 1, TRUE, 1, NOW(), FALSE);
SET @course_id = LAST_INSERT_ID();



-- ===================================================================
-- LESSON 1: OpenMRS Overview & Architecture
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"OpenMRS Overview & Architecture","fr":"Aperçu et architecture d''OpenMRS"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"OpenMRS (Open Medical Record System) is a collaborative open-source project designed to develop software that supports healthcare delivery in resource-constrained environments around the world. It began in 2004 as a partnership between the Regenstrief Institute and Partners In Health to address the lack of medical record systems in developing countries.","fr":"OpenMRS (Open Medical Record System) est un projet collaboratif open-source conçu pour développer des logiciels qui soutiennent la prestation de soins de santé dans des environnements à ressources limitées du monde entier. Il a commencé en 2004 comme un partenariat entre le Regenstrief Institute et Partners In Health pour répondre au manque de systèmes de dossiers médicaux dans les pays en développement."}},{"type":"heading","content":{"en":"Mission and Key Characteristics","fr":"Mission et caractéristiques clés"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"OpenMRS aims to improve health care delivery in resource-constrained environments by coordinating a global community to create and support open-source software. The platform is used in over 100 countries and supports millions of patient records worldwide.","fr":"OpenMRS vise à améliorer la prestation de soins de santé dans les environnements à ressources limitées en coordonnant une communauté mondiale pour créer et soutenir des logiciels open-source. La plateforme est utilisée dans plus de 100 pays et prend en charge des millions de dossiers de patients dans le monde."}},{"type":"list","items":[{"en":"Open Source: Free to use, modify, and distribute under the Mozilla Public License","fr":"Open Source : Gratuit à utiliser, modifier et distribuer sous la licence publique Mozilla"},{"en":"Community-Driven: Developed and maintained by a global community of volunteers","fr":"Communautaire : Développé et maintenu par une communauté mondiale de bénévoles"},{"en":"Flexible: Highly customizable to meet diverse healthcare needs","fr":"Flexible : Hautement personnalisable pour répondre à divers besoins de santé"},{"en":"Modular: Extensible through a module system","fr":"Modulaire : Extensible grâce à un système de modules"}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Core Data Architecture","fr":"Architecture de données principale"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Understanding OpenMRS architecture is essential for effective use. The system is built around four core data entities that work together to capture and organize patient information:","fr":"Comprendre l''architecture d''OpenMRS est essentiel pour une utilisation efficace. Le système est construit autour de quatre entités de données principales qui travaillent ensemble pour capturer et organiser les informations des patients :"}},{"type":"list","items":[{"en":"Patients: Represent individuals receiving care, containing demographic information and unique identifiers","fr":"Patients : Représentent les individus recevant des soins, contenant des informations démographiques et des identifiants uniques"},{"en":"Encounters: Record interactions between patients and healthcare providers at specific points in time","fr":"Rencontres : Enregistrent les interactions entre les patients et les prestataires de soins à des moments précis"},{"en":"Observations: Capture individual data points collected during encounters, such as vital signs or lab results","fr":"Observations : Capturent des points de données individuels collectés pendant les rencontres, tels que les signes vitaux ou les résultats de laboratoire"},{"en":"Concepts: Define the standardized medical terminology used throughout the system (the vocabulary)","fr":"Concepts : Définissent la terminologie médicale standardisée utilisée dans tout le système (le vocabulaire)"}],"properties":{"ordered":false}},{"type":"paragraph","content":{"en":"These entities form a hierarchy: A Patient has multiple Encounters, each Encounter contains multiple Observations, and each Observation is defined by a Concept. This structure ensures data consistency and enables reporting.","fr":"Ces entités forment une hiérarchie : Un Patient a plusieurs Rencontres, chaque Rencontre contient plusieurs Observations, et chaque Observation est définie par un Concept. Cette structure garantit la cohérence des données et permet des rapports."}},{"type":"alert","content":{"en":"Remember: Understanding this data model is crucial. Every piece of clinical data you enter follows this Patient → Encounter → Observation → Concept structure.","fr":"N''oubliez pas : Comprendre ce modèle de données est crucial. Chaque donnée clinique que vous saisissez suit cette structure Patient → Rencontre → Observation → Concept."},"properties":{"variant":"info"}}]', 1, 1, NOW(), FALSE);
SET @lesson_id_1 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 1: Core Architecture Understanding (Matching)
-- ===================================================================
VALUES (UUID(), 'MATCHING', '{"instructions":{"en":"Match each OpenMRS data entity with its correct description. Understanding these core components is essential for working with the system.","fr":"Associez chaque entité de données OpenMRS à sa description correcte. Comprendre ces composants de base est essentiel pour travailler avec le système."},"leftItems":[{"id":"1","text":{"en":"Patient","fr":"Patient"}},{"id":"2","text":{"en":"Encounter","fr":"Rencontre"}},{"id":"3","text":{"en":"Observation","fr":"Observation"}},{"id":"4","text":{"en":"Concept","fr":"Concept"}}],"rightItems":[{"id":"a","text":{"en":"An individual data point captured during a visit (e.g., temperature reading)","fr":"Un point de données individuel capturé lors d''une visite (p. ex., lecture de température)"}},{"id":"b","text":{"en":"A standardized term that defines what type of data is being recorded","fr":"Un terme standardisé qui définit le type de données enregistré"}},{"id":"c","text":{"en":"An individual receiving healthcare services in the system","fr":"Un individu recevant des services de santé dans le système"}},{"id":"d","text":{"en":"An interaction between a patient and healthcare provider at a specific time","fr":"Une interaction entre un patient et un prestataire de soins à un moment précis"}}]}', '{"correctMatches":{"1":"c","2":"d","3":"a","4":"b"}}', '{"correct":{"en":"Excellent! You understand the core OpenMRS architecture. This hierarchy (Patient → Encounter → Observation → Concept) is the foundation of all data in OpenMRS. Every clinical data point follows this structure, ensuring consistency and enabling reporting.","fr":"Excellent ! Vous comprenez l''architecture de base d''OpenMRS. Cette hiérarchie (Patient → Rencontre → Observation → Concept) est la fondation de toutes les données dans OpenMRS. Chaque point de données cliniques suit cette structure, garantissant la cohérence et permettant des rapports."},"incorrect":{"en":"Review the Core Data Architecture section. Remember: Patients have Encounters, Encounters contain Observations, and each Observation is defined by a Concept. Think about the relationship: who (Patient), when (Encounter), what was measured (Observation), and how we define it (Concept).","fr":"Révisez la section Architecture de données principale. Rappel : Les Patients ont des Rencontres, les Rencontres contiennent des Observations, et chaque Observation est définie par un Concept. Pensez à la relation : qui (Patient), quand (Rencontre), ce qui a été mesuré (Observation), et comment nous le définissons (Concept)."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_1 = LAST_INSERT_ID();


-- ===================================================================
-- LESSON 2: Using OpenMRS
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Using OpenMRS","fr":"Utilisation d''OpenMRS"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"OpenMRS provides an intuitive web-based interface that healthcare workers use to manage patient care. Understanding basic navigation and the clinical workflow will help you work efficiently with the system.","fr":"OpenMRS fournit une interface web intuitive que les professionnels de santé utilisent pour gérer les soins aux patients. Comprendre la navigation de base et le flux de travail clinique vous aidera à travailler efficacement avec le système."}},{"type":"heading","content":{"en":"Navigation Essentials","fr":"Éléments essentiels de navigation"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"OpenMRS 3 uses a modern microfrontend architecture with key navigation elements:","fr":"OpenMRS 3 utilise une architecture microfrontend moderne avec des éléments de navigation clés :"}},{"type":"list","items":[{"en":"App Menu (top right): Access all system modules including System Administration, Dispensing, and Fast Data Entry","fr":"Menu d''applications (en haut à droite) : Accédez à tous les modules système, y compris Administration système, Dispensation et Saisie rapide de données"},{"en":"Patient Search: Find existing patients by name, identifier, or demographic information","fr":"Recherche de patients : Trouvez des patients existants par nom, identifiant ou informations démographiques"},{"en":"Patient Dashboard: View comprehensive patient information including visits, forms, and clinical summaries","fr":"Tableau de bord patient : Affichez des informations complètes sur le patient, y compris les visites, les formulaires et les résumés cliniques"}],"properties":{"ordered":false}},{"type":"heading","content":{"en":"Clinical Workflow","fr":"Flux de travail clinique"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Most clinical work in OpenMRS follows a standard workflow that mirrors real-world healthcare processes:","fr":"La plupart du travail clinique dans OpenMRS suit un flux de travail standard qui reflète les processus de soins de santé du monde réel :"}},{"type":"list","items":[{"en":"Register Patient: Create a new patient record with demographic information and identifiers","fr":"Enregistrer le patient : Créez un nouveau dossier patient avec des informations démographiques et des identifiants"},{"en":"Start Visit/Encounter: Record that the patient has arrived for care at a specific time and location","fr":"Démarrer la visite/rencontre : Enregistrez que le patient est arrivé pour des soins à un moment et un endroit précis"},{"en":"Capture Clinical Data: Use forms to record vital signs, symptoms, diagnoses, and treatment plans","fr":"Capturer les données cliniques : Utilisez des formulaires pour enregistrer les signes vitaux, les symptômes, les diagnostics et les plans de traitement"},{"en":"Complete Visit: Finalize the encounter and make the data available for reporting","fr":"Terminer la visite : Finalisez la rencontre et rendez les données disponibles pour les rapports"}],"properties":{"ordered":true}},{"type":"paragraph","content":{"en":"This workflow creates a clear audit trail of patient care. Each visit generates an encounter record, and all data collected during that visit is linked to both the encounter and the patient, maintaining data integrity throughout the system.","fr":"Ce flux de travail crée une piste d''audit claire des soins aux patients. Chaque visite génère un enregistrement de rencontre, et toutes les données collectées pendant cette visite sont liées à la fois à la rencontre et au patient, maintenant l''intégrité des données dans tout le système."}},{"type":"heading","content":{"en":"Integration with Daily Work","fr":"Intégration au travail quotidien"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"OpenMRS is designed to integrate into clinical settings. The system supports multiple concurrent users, offline capabilities in some implementations, and can be customized to match local healthcare workflows. Different user roles can be configured with appropriate permissions to ensure that staff only access features relevant to their responsibilities.","fr":"OpenMRS est conçu pour s''intégrer dans les environnements cliniques. Le système prend en charge plusieurs utilisateurs simultanés, des capacités hors ligne dans certaines implémentations et peut être personnalisé pour correspondre aux flux de travail de santé locaux. Différents rôles d''utilisateur peuvent être configurés avec des autorisations appropriées pour garantir que le personnel n''accède qu''aux fonctionnalités pertinentes pour ses responsabilités."}},{"type":"alert","content":{"en":"Tip: OpenMRS 3 is the modern frontend interface, while OpenMRS 2 provides the backend services. When you access System Administration → Legacy Admin, you are accessing OpenMRS 2 functionality for advanced configuration tasks.","fr":"Conseil : OpenMRS 3 est l''interface frontend moderne, tandis qu''OpenMRS 2 fournit les services backend. Lorsque vous accédez à Administration système → Administration héritée, vous accédez aux fonctionnalités d''OpenMRS 2 pour des tâches de configuration avancées."},"properties":{"variant":"info"}}]', 1, 1, NOW(), FALSE);
SET @lesson_id_2 = LAST_INSERT_ID();



-- ===================================================================
-- LESSON 3: Key Components Overview
-- ===================================================================
VALUES (UUID(), '[{"type":"heading","content":{"en":"Key Components Overview","fr":"Aperçu des composants clés"},"properties":{"level":1}},{"type":"paragraph","content":{"en":"OpenMRS includes three critical components that work together to enable comprehensive patient care management. Understanding these components is essential as you will work with them extensively in your OpenMRS implementation.","fr":"OpenMRS comprend trois composants critiques qui travaillent ensemble pour permettre une gestion complète des soins aux patients. Comprendre ces composants est essentiel car vous travaillerez avec eux de manière extensive dans votre implémentation OpenMRS."}},{"type":"heading","content":{"en":"Concept Dictionary","fr":"Dictionnaire de concepts"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"The Concept Dictionary is the central repository for all medical terminology used in OpenMRS. It contains standardized concepts that represent clinical and administrative data. Every question on a form, every observation recorded, and every diagnosis made references a concept from this dictionary. This standardization ensures consistent data collection across your entire implementation and enables accurate reporting and analysis.","fr":"Le dictionnaire de concepts est le référentiel central de toute la terminologie médicale utilisée dans OpenMRS. Il contient des concepts standardisés qui représentent des données cliniques et administratives. Chaque question sur un formulaire, chaque observation enregistrée et chaque diagnostic posé fait référence à un concept de ce dictionnaire. Cette standardisation garantit une collecte de données cohérente dans toute votre implémentation et permet des rapports et analyses précis."}},{"type":"heading","content":{"en":"Forms","fr":"Formulaires"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"Forms are structured interfaces for data collection. They guide healthcare workers through capturing patient information in a consistent way. Each form is built using concepts from the dictionary, which means the data collected is automatically standardized. Forms can be customized to match your workflows, from simple vital signs entry to complex clinical assessments. When a form is submitted, it creates an encounter with observations linked to the patient record.","fr":"Les formulaires sont des interfaces structurées pour la collecte de données. Ils guident les professionnels de santé à travers la capture d''informations sur les patients de manière cohérente. Chaque formulaire est construit en utilisant des concepts du dictionnaire, ce qui signifie que les données collectées sont automatiquement standardisées. Les formulaires peuvent être personnalisés pour correspondre à vos flux de travail, de la saisie simple des signes vitaux aux évaluations cliniques complexes. Lorsqu''un formulaire est soumis, il crée une rencontre avec des observations liées au dossier du patient."}},{"type":"heading","content":{"en":"Reports","fr":"Rapports"},"properties":{"level":2}},{"type":"paragraph","content":{"en":"The reporting system transforms collected data into insights. Because all data is captured using standardized concepts, OpenMRS can generate reports for clinical management, program monitoring, and research. Reports can track patient outcomes, monitor program performance, identify trends, and support evidence-based decision making. The standardized data model makes it possible to aggregate information across time periods, locations, and patient populations.","fr":"Le système de rapports transforme les données collectées en informations. Parce que toutes les données sont capturées en utilisant des concepts standardisés, OpenMRS peut générer des rapports pour la gestion clinique, le suivi des programmes et la recherche. Les rapports peuvent suivre les résultats des patients, surveiller les performances des programmes, identifier les tendances et soutenir la prise de décision basée sur les preuves. Le modèle de données standardisé permet d''agréger les informations sur des périodes de temps, des emplacements et des populations de patients."}},{"type":"alert","content":{"en":"Important: These three components are interconnected. The Concept Dictionary provides the vocabulary, Forms use that vocabulary to collect data, and Reports analyze that standardized data. Understanding how they work together is key to effective OpenMRS use.","fr":"Important : Ces trois composants sont interconnectés. Le dictionnaire de concepts fournit le vocabulaire, les Formulaires utilisent ce vocabulaire pour collecter des données, et les Rapports analysent ces données standardisées. Comprendre comment ils fonctionnent ensemble est la clé d''une utilisation efficace d''OpenMRS."},"properties":{"variant":"success"}}]', 1, 1, NOW(), FALSE);
SET @lesson_id_3 = LAST_INSERT_ID();



-- ===================================================================
-- EXERCISE 2: Key Components Understanding (Matching)
-- ===================================================================
VALUES (UUID(), 'MATCHING', '{"instructions":{"en":"Match each OpenMRS component with its primary function. These are the three critical components you learned about in the Key Components lesson.","fr":"Associez chaque composant OpenMRS à sa fonction principale. Ce sont les trois composants critiques dont vous avez appris dans la leçon Composants clés."},"leftItems":[{"id":"1","text":{"en":"Concept Dictionary","fr":"Dictionnaire de concepts"}},{"id":"2","text":{"en":"Forms","fr":"Formulaires"}},{"id":"3","text":{"en":"Reports","fr":"Rapports"}}],"rightItems":[{"id":"a","text":{"en":"Structured interfaces that guide data collection using standardized concepts","fr":"Interfaces structurées qui guident la collecte de données en utilisant des concepts standardisés"}},{"id":"b","text":{"en":"Central repository for all medical terminology used throughout the system","fr":"Référentiel central de toute la terminologie médicale utilisée dans le système"}},{"id":"c","text":{"en":"Transform collected data into insights for clinical management and research","fr":"Transforment les données collectées en informations pour la gestion clinique et la recherche"}}]}', '{"correctMatches":{"1":"b","2":"a","3":"c"}}', '{"correct":{"en":"Excellent! You understand how the three key components work together. The Concept Dictionary provides the medical vocabulary, Forms use that vocabulary to collect data consistently, and Reports analyze that standardized data to generate insights. This interconnection is what makes OpenMRS powerful - standardized terminology flows through the entire system from data collection to analysis. In the specialized courses (Concept Dictionary Management and Form Design), you will learn to work with these components in detail.","fr":"Excellent ! Vous comprenez comment les trois composants clés fonctionnent ensemble. Le Dictionnaire de concepts fournit le vocabulaire médical, les Formulaires utilisent ce vocabulaire pour collecter des données de manière cohérente, et les Rapports analysent ces données standardisées pour générer des informations. Cette interconnexion est ce qui rend OpenMRS puissant - la terminologie standardisée circule dans tout le système, de la collecte de données à l''analyse. Dans les cours spécialisés (Gestion du dictionnaire de concepts et Conception de formulaires), vous apprendrez à travailler avec ces composants en détail."},"incorrect":{"en":"Review the Key Components Overview lesson. Remember: (1) The Concept Dictionary is the terminology repository that stores all medical terms, (2) Forms are the data collection interfaces that use concepts to standardize what is captured, and (3) Reports analyze the standardized data to provide insights. Think about the flow: terminology → data collection → analysis. Each component has a specific role in this workflow.","fr":"Révisez la leçon Aperçu des composants clés. Rappel : (1) Le Dictionnaire de concepts est le référentiel de terminologie qui stocke tous les termes médicaux, (2) Les Formulaires sont les interfaces de collecte de données qui utilisent des concepts pour standardiser ce qui est capturé, et (3) Les Rapports analysent les données standardisées pour fournir des informations. Pensez au flux : terminologie → collecte de données → analyse. Chaque composant a un rôle spécifique dans ce flux de travail."}}', TRUE, 1, NOW(), FALSE);
SET @exercise_id_2 = LAST_INSERT_ID();


